   def ProcessXML(self, class_list):
      # for each attribs class
      for attribs_class in class_list.values():
         self.GenerateGenericAttribsFile(attribs_class)
   
   # SLB 28.nov.2018 CR.7698; Modified to support building an 'outer' attribs class which uses another 'outer'
   # attribs class for a base class.
   # SLB 24.sep.2021 CR.30781; base_class_name needs the "code name" assigned to it vs the AttribsXml key 
   # name.
   def GenerateAttribsClass(self, attribs_class, inner_class, derived_class):
      # class declaration header
      
      class_text = CreateComments(attribs_class['comments'])

      class_name = attribs_class['code_class_name']                                                # CR.7698; added.
      base_class_name = attribs_class['base_class_code_name']                                      # CR.30781; modified. CR.7698; added.
         
      if (not derived_class):
         if len(base_class_name)==0:                                                               # CR.7698; added if; modified statements within.
            class_text += """public class %s : SpdAttribsBase\n{\n   public static string ClassName = "%s";\n   \n""" % (class_name, attribs_class['name'])
            class_text += """   public %s() : \n      base(ClassName)\n   {\n      ;""" % (class_name,)
         else:                                                                                     # CR.7698; added new else:
            # CR.7698; In this form, constructor sets ClassName.
            class_text += """public class %s : %s\n{\n   \n""" % (class_name, base_class_name)     # CR.7698; added.
            class_text += """   public %s() \n   {\n      ClassName = "%s";""" % (class_name, attribs_class['name']) # CR.7698; added.
            
         class_text += self.GenerateClassAliasedResourceInitializers(attribs_class['members']) ;
         class_text += """\n   }\n   \n"""
         
         # Create constructor with parameters
         if len(base_class_name)==0:                                                               # CR.7698; added if; modified statements within.
            class_text += """   public %s(string tagName, bool requiredButNotUsed) : \n      base(ClassName)\n   {\n      m_TagName = tagName;""" % (class_name,)
            class_text += self.GenerateClassAliasedResourceInitializers(attribs_class['members']) ;
            class_text += """\n   }\n   \n"""
         #else:                                                                                     # CR.7698; added new else:
            #class_text += """   public %s() \n   {\n      ClassName = "%s";""" % (class_name, attribs_class['name']) # CR.7698; added.
      else:
         class_text += """public class %s : %s\n{\n   public new static string ClassName = "%s";\n   \n""" % (class_name, base_class_name, attribs_class['name'])
         class_text += """   public %s() : \n      base()\n   {\n""" % (class_name,)               # CR.7698; modified.
         
         # set the derived class defaults (defaults are overriden here)
         class_text += "      /* default overrides */\n"
         class_text += "      m_ClassName = ClassName;\n"
         # set member variables in the constructor
         class_text += "      /* member variables (if any) */\n"
         for member in OutputOrderDictionaryValues(attribs_class['members']):
            member_info = self.ComputeMemberInfo(attribs_class, member)
            class_text += '      %s %s = new %s("%s", %s);\n' % (member_info['type'],member_info['name'],member_info['type'],member_info['tagname'],member_info['default'])              
         class_text += self.GenerateClassAliasedResourceInitializers(attribs_class['members']) ;
         class_text += """   }\n   \n""" 
         
         # Create constructor with parameters
         class_text += """   public %s(string tagName, bool requiredButNotUsed) : \n      base()\n   {\n""" % (class_name,)               # CR.7698; modified.
         # set the derived class defaults (defaults are overriden here)
         class_text += "      /* default overrides */\n"
         class_text += "      m_ClassName = ClassName;\n"
         class_text += "      m_TagName = tagName;\n"
         # set member variables in the constructor
         class_text += "      /* member variables (if any) */\n"
         for member in OutputOrderDictionaryValues(attribs_class['members']):
            member_info = self.ComputeMemberInfo(attribs_class, member)
            class_text += '      %s %s = new %s("%s", %s);\n' % (member_info['type'],member_info['name'],member_info['type'],member_info['tagname'],member_info['default'])              
         class_text += self.GenerateClassAliasedResourceInitializers(attribs_class['members']) ;
         class_text += """   }\n   \n""" 
      
      # declare typedefs (nested attribs classes and enums) and collect them for use later
      if (not derived_class):
         for typedef in OutputOrderDictionaryValues(attribs_class['typedefs']):
            class_text += IndentTextTabs(self.GenerateTypedef(typedef, attribs_class['predefined_types']),1)
         
         class_text += "   \n"
         
         # declare the various member variables
         for member in OutputOrderDictionaryValues(attribs_class['members']):
            member_info = self.ComputeMemberInfo(attribs_class,member)
            class_text += '   public %s %s = new %s("%s", %s%s);\n' % (member_info['type'],member_info['name'],member_info['type'],member_info['tagname'],member_info['default'],self.GenerateNumEncodingIfNeeded(member))
      
      class_text += "\n"
      
      # close out the class declaration
      class_text += '};\n'
      
      return class_text

   def GenerateNumEncodingIfNeeded(self,member):      
      if (member.has_key('numencoding') and member['numencoding'] == 'decimal'):
          return ', NumEncoding.Decimal'
      else :
          return ''
  
   # SLB 24.sep.2021 CR.39781; Changes to match changes in input format... Now typedef info for 'derived_class' 
   # types is in the same location and format as that for 'class' types.
   # SLB 14.apr.2025 CR.33850.V01; Enhanced to generate new AttribsMemberByteArrayList class for List<byte> 
   # member types.
   #
   # typedef = {}         # {name, type, enum, inner_class, derived_class}
   def GenerateTypedef(self, typedef, predefined_types):
      typedef_text = ''
      
      if (typedef['type'] == 'enum'):
         typedef_text += '[FlagsAttribute]\npublic enum %s\n{\n' % (typedef['name'],)
         for enum in typedef['enum']:
            typedef_text += '   %s = %s,\n' % (enum['name'],enum['value'])
         typedef_text += '};\n\n'
         
         # generate the AttribsMember class
         typedef_text += 'public class AttribsMemberEnum_%s : AttribsMemberEnum<%s>\n{\n   public AttribsMemberEnum_%s(string keyName, %s defaultVal) :\n      base(keyName, defaultVal)\n   {\n      ;\n   }\n   \n' % (typedef['name'],typedef['name'],typedef['name'],typedef['name'])
         typedef_text += '   protected static Dictionary<string, %s> m_MapAliasToEnum;\n' % (typedef['name'])
         typedef_text += '   protected static Dictionary<%s, string> m_MapEnumToAlias;\n' % (typedef['name'])
         typedef_text += '   protected static SortedList<int, string> m_MapOrderingIndexToAlias;\n'
         typedef_text += '   protected static Dictionary<string, int> m_MapAliasToIndex;\n'
         typedef_text += '   protected static Dictionary<%s, int> m_MapEnumToIndex;\n' % (typedef['name'])
         typedef_text += '   static AttribsMemberEnum_%s()\n   {\n' % (typedef['name'],)
         typedef_text += '      m_MapAliasToEnum = new Dictionary<string, %s>();\n' % (typedef['name'])
         typedef_text += '      m_MapEnumToAlias = new Dictionary<%s, string>();\n' % (typedef['name'])
         typedef_text += '      m_MapOrderingIndexToAlias = new SortedList<int, string>();   // map of the ordering indexes from the xml file to aliases. The ordering indexes are not guranteed to be continuous or 0 based. \n'
         typedef_text += '      m_MapAliasToIndex = new Dictionary<string, int>();   // This is different than the ordering index. This function takes an alias and returns what index it is in the GetAliases() list. \n'
         typedef_text += '      m_MapEnumToIndex = new Dictionary<%s, int>();   // This is different than the ordering index. This function takes an alias and returns what index it is in the GetAliases() list. \n' % (typedef['name'])
         alias_ordering = {}
         enum_ordering = {}
         for enum in typedef['enum']:
            typedef_text += '      m_MapAliasToEnum.Add("%s",%s.%s);\n' % (enum['alias'],typedef['name'],enum['name'])
            typedef_text += '      m_MapEnumToAlias.Add(%s.%s,"%s");\n' % (typedef['name'],enum['name'],enum['alias'])
            typedef_text += '      m_MapOrderingIndexToAlias.Add(%s,"%s");\n' % (enum['order'],enum['alias'])
            # build the data used to create m_MapAliasToIndex
            alias_ordering[int(enum['order'])] = enum['alias']
            enum_ordering[int(enum['order'])] = '%s.%s' % (typedef['name'],enum['name'])
         index = 0
         for alias in alias_ordering.values():
            typedef_text += '      m_MapAliasToIndex.Add("%s",%s);\n' % (alias,index)   #alias_ordering[alias],alias)
            index += 1
         index = 0
         for enum in enum_ordering.values():
            typedef_text += '      m_MapEnumToIndex.Add(%s,%s);\n' % (enum,index)   #alias_ordering[alias],alias)
            index += 1
         
         typedef_text += '   }\n   \n'
         
         typedef_text += """
   public static string GetAlias(%s enum_value)
   {
      return m_MapEnumToAlias[enum_value];
   }
   public static StringCollection GetAliases()
   {
      StringCollection alias_list = new StringCollection();
      foreach (string alias in m_MapOrderingIndexToAlias.Values)
      {
         alias_list.Add(alias);
      }
      return alias_list;
   }
   public static %s GetEnumValueFromAlias(string alias)
   {
      return m_MapAliasToEnum[alias];
   }
   public static int GetIndexFromAlias(string alias)
   {
      return m_MapAliasToIndex[alias];
   }
   public static int GetIndexFromEnum(%s enum_value)
   {
      return m_MapEnumToIndex[enum_value];
   }
   
   public string GetAlias()
   {
      return GetAlias(TVal);
   }
   public void SetEnumValueFromAlias(string alias)
   {
      EVal = GetEnumValueFromAlias(alias);
   }\n\n}""" % (typedef['name'],typedef['name'],typedef['name'])
      elif (typedef['type'] == 'class'):
         typedef_text += self.GenerateAttribsClass(typedef['inner_class'],1,0)
         typedef_text += '\n'
         #typedef_text += """public class AttribsMemberAttribsClass_%s : AttribsMemberAttribsClass\n{\n   public AttribsMemberAttribsClass_%s(string keyName, %s defaultVal) : \n      base(keyName, defaultVal)\n   {\n      ;\n   }\n   \n   public static implicit operator %s(AttribsMemberAttribsClass_%s t)\n   {\n      return (%s)t.m_tVal;\n   }\n\n   public %s TVal\n   {\n      get {return this;}\n      set {m_tVal = (Object)value;}\n   }\n}\n""" % (typedef['name'],typedef['name'],typedef['name'],typedef['name'],typedef['name'],typedef['name'],typedef['name'])
      elif (typedef['type'] == 'derived'):
         typedef_text += self.GenerateAttribsClass(typedef['inner_class'],1,1)                     # CR.30781; modified.
         typedef_text += '\n'
         #typedef_text += """public class AttribsMemberAttribsClass_%s : AttribsMemberAttribsClass\n{\n   public AttribsMemberAttribsClass_%s(string keyName, %s defaultVal) : \n      base(keyName, defaultVal)\n   {\n      ;\n   }\n   \n   public static implicit operator %s(AttribsMemberAttribsClass_%s t)\n   {\n      return (%s)t.m_tVal;\n   }\n\n   public %s TVal\n   {\n      get {return this;}\n      set {m_tVal = (Object)value;}\n   }\n}\n""" % (typedef['name'],typedef['name'],typedef['name'],typedef['name'],typedef['name'],typedef['name'],typedef['name'])
      elif (typedef['type'] == 'collection' and typedef['collection']['type']=='List'):
         value_type = typedef['collection']['value_type']
         if value_type != 'byte[]':                                                                # CR.33850.V01; added.
            if (self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])):
               value_type = self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])
            typedef_text += '\npublic class %s : AttribsMemberGenericList<%s> {public %s(string keyName, List<%s> defaultVal) : base(keyName, defaultVal){;} }\n' % (typedef['name'], value_type, typedef['name'], value_type)
         else:                                                                                     # CR.33850.V01; added.
            typedef_text += '\npublic class %s : AttribsMemberByteArrayList {public %s(string keyName, List<%s> defaultVal) : base(keyName, defaultVal){;} }\n' % (typedef['name'], typedef['name'], value_type)  # CR.33850.V01; added.
      elif (typedef['type'] == 'collection' and typedef['collection']['type']=='SlimList'):
         value_type = typedef['collection']['value_type']
         if (self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])):
            value_type = self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])
         typedef_text += '\npublic class %s : AttribsMemberStreamlinedList<%s> {public %s(string keyName, List<%s> defaultVal) : base(keyName, defaultVal){;} }\n' % (typedef['name'], value_type, typedef['name'], value_type)
      elif (typedef['type'] == 'collection' and typedef['collection']['type']=='Map'):
         key_type = typedef['collection']['key_type']
         if (self.TranslateMemberTypeUnderlying(typedef['collection']['key_type'])):
            key_type = self.TranslateMemberTypeUnderlying(typedef['collection']['key_type'])
         value_type = typedef['collection']['value_type']
         if (self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])):
            value_type = self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])
         typedef_text += '\npublic class %s : AttribsMemberGenericMap<%s, %s> {public %s(string keyName, Dictionary<%s, %s> defaultVal) : base(keyName, defaultVal){;} }\n' % (typedef['name'], key_type, value_type, typedef['name'], key_type, value_type)
      elif (typedef['type'] == 'collection' and typedef['collection']['type']=='SlimMap'):
         key_type = typedef['collection']['key_type']
         if (self.TranslateMemberTypeUnderlying(typedef['collection']['key_type'])):
            key_type = self.TranslateMemberTypeUnderlying(typedef['collection']['key_type'])
         value_type = typedef['collection']['value_type']
         if (self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])):
            value_type = self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])
         typedef_text += '\npublic class %s : AttribsMemberStreamlinedMap<%s, %s> {public %s(string keyName, Dictionary<%s, %s> defaultVal) : base(keyName, defaultVal){;} }\n' % (typedef['name'], key_type, value_type, typedef['name'], key_type, value_type)
      else:
         pass
      
      return typedef_text
   
   # returns [name, typedef_type, type, default, tagname]
   # SLB 14.apr.2016 CR.21425; Modified to treat DatTime type as String.
   # SLB 24.sep.2021 CR.30781; Changes to support attribs_class['predefined_types'] correctly.
   def ComputeMemberInfo(self, attribs_class, member):
      attrib_name = member['name']
      attrib_tagname = member['tagname']
      attrib_default = member['default']
      attrib_type = member['type']
      attrib_type_underlying = member['type']
      typedef = None
      typedef_type = None
      collection_info = None
      typedef_collection_type = None
      attrib_type_found = False
      
      # translate the default value
      if (attribs_class['typedefs'].has_key(attrib_type)):
         attrib_type_found = True
         typedef = attribs_class['typedefs'][attrib_type]
         typedef_type = typedef['type']
         try:
            typedef_collection_type = typedef['collection']['type']
         except:
            pass
      elif (attribs_class['predefined_types'].has_key(attrib_type)):
         # CR.30781; this should be the same as the 'typedefs' case, just assign typedef from the
         # 'predefined_types' vs the 'typedefs'
         # Note that predefined_types are defintions that are valid for the scope of this class.
         # e.g. any types defined in a base class or a containing class will be here.
         # This is different from typedefs in that typedefs are types which were defined within
         # this class (ie. not inherited)
         attrib_type_found = True
         typedef = attribs_class['predefined_types'][attrib_type]                                   # CR.30781; added back.
         typedef_type = typedef['type']                                                             # CR.30781; modified.
         try:                                                                                       # CR.30781; added back.
            typedef_collection_type = typedef['collection']['type']                                 # CR.30781; added back.
         except:                                                                                    # CR.30781; added back.
            pass                                                                                    # CR.30781; added back.

      if (attrib_type_found):         
         if (typedef_type=='class'):
            attrib_default = 'false'
            #attrib_default = 'new %s()' % (attrib_type,)
         elif (typedef_type=='derived'):
            attrib_default = 'false'
            #attrib_default = 'new %s()' % (attrib_type,)
         elif (typedef_type=='enum'):
            attrib_default = '%s.%s' % (attrib_type,attrib_default)
         elif (typedef_type == 'collection'):
            value_type = typedef['collection']['value_type']
            if (self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])):
               value_type = self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])
            if (typedef_collection_type == 'List' or typedef_collection_type == 'SlimList'):
               attrib_default = 'new List<%s>()' % (value_type)
            elif (typedef_collection_type == 'Map' or typedef_collection_type == 'SlimMap'):
               key_type = typedef['collection']['key_type']
               if (self.TranslateMemberTypeUnderlying(typedef['collection']['key_type'])):
                  key_type = self.TranslateMemberTypeUnderlying(typedef['collection']['key_type'])
               attrib_default = 'new Dictionary<%s, %s>()' % (key_type, value_type)
         else:
            attrib_default = '0 /* (2)?-> %s %s */' % (attrib_type,str(typedef))
      elif (attrib_type == 'string'):
         attrib_default = '"%s"' % (EscapeCStringLiteral(attrib_default),)
      elif (attrib_type == 'xmlstring'):
         attrib_default = '"%s"' % (EscapeCStringLiteral(attrib_default),)
      elif (attrib_type == 'encrypted'):
         attrib_default = '"%s"' % (EscapeCStringLiteral(attrib_default),)
      elif (attrib_type == 'DateTime'):
         attrib_default = 'new DateTime()'
      elif (attrib_type[:5] == 'list('):
         attrib_default = 'new ArrayList()'
      elif (attrib_type[:4] == 'map('):
         attrib_default = 'new Hashtable()'
      elif (attrib_type == 'byte[]'):
         attrib_default = 'new byte[]%s' % (EncodeBufferLiteral(attrib_default)[0],)
      elif (                                                                                       # CR.15891.V04; modified.  
         attrib_type == 'AliasFolder' or
         attrib_type == 'AliasFile' or
         attrib_type == 'AliasPclMetaDriver' or                                                    # CR.15891.V04; added.  
         attrib_type == 'AliasPclMetaMedia' or                                                     # CR.15891.V04; added.
         attrib_type == 'AliasPclMetaOutput' or                                                    # CR.15891.V04; added.
         attrib_type == 'AliasAfpdsSharedResource' or                                              # CR.15891.V04; added.
         attrib_type == 'AliasRje3211Fcb' or                                                       # CR.15891.V04; added.
         attrib_type == 'AliasMachineName' or                                                      # CR.15891.V04; added.
         attrib_type == 'AliasDbsCheckpoint' or                                                    # CR.15891.V04; added.
         attrib_type == 'AliasDbsMonitor'                                                          # CR.15891.V04; added.
         ):
         attrib_default = '"%s"' % (EscapeCStringLiteral(attrib_default),)
      elif (attrib_type not in self.type_map):
         attrib_default = 'new %s()/*<-?(3)*/' % (attrib_type,)
      
      # translate the type
      attrib_translated_type = self.TranslateMemberType(attrib_type)
      if (attrib_translated_type):
         attrib_type = attrib_translated_type
      else:
         if (attrib_type_found):
            if (typedef_type == 'enum'):
               attrib_type = 'AttribsMemberEnum_%s' % (attrib_type)
            elif (typedef_type == 'class'):
               attrib_type = attrib_type
               #attrib_type = 'AttribsMemberAttribsClass_%s' % (attrib_type)
            elif (typedef_type == 'derived'):
               attrib_type = attrib_type
               #attrib_type = 'AttribsMemberAttribsClass_%s' % (attrib_type)
            elif (typedef_type == 'collection'):
               if (typedef_collection_type == 'List' or typedef_collection_type == 'SlimList'):
                  value_type = typedef['collection']['value_type']
                  if (self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])):
                     value_type = self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])
                  collection_info = {'type': typedef_collection_type, 'value_type': value_type}                            
               elif (typedef_collection_type == 'Map' or typedef_collection_type == 'SlimMap'):
                  key_type = typedef['collection']['key_type']
                  if (self.TranslateMemberTypeUnderlying(typedef['collection']['key_type'])):
                     key_type = self.TranslateMemberTypeUnderlying(typedef['collection']['key_type'])
                  value_type = typedef['collection']['value_type']
                  if (self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])):
                     value_type = self.TranslateMemberTypeUnderlying(typedef['collection']['value_type'])
                  collection_info = {'type': typedef_collection_type, 'key_type': key_type, 'value_type': value_type}
               # attrib_type = 'AttribsMemberGenericList' % (attrib_type,)
            else:
               # This is what it used to be --> attrib_type = '%s/*Unknown(0)*/' % (attrib_type,)
               attrib_type = 'AttribsMemberAttribsClass_%s/*<-?(0)*/' % (attrib_type)
         else:
            # This is what it used to be --> attrib_type = '%s /*Unknown(1) */' % (attrib_type,)
            attrib_type = 'AttribsMemberAttribsClass_%s/*<-?(1)*/' % (attrib_type)
      
      return {'name': attrib_name, 'typedef_type': typedef_type, 'type': attrib_type, 'default': attrib_default, 'tagname': attrib_tagname, 'typedef': typedef, 'collection_info': collection_info}
   
   def ComputeFilePath(self, filename_base):
      return 'LicAttribsCS\\' + self.ComputeFileName(filename_base)
   def ComputeFileName(self, filename_base):
      return filename_base + '.cs'
   
   def GenerateGenericAttribsFile(self, attribs_class):
      # generate and write the header file text
      self.WriteFileIfDifferent(self.ComputeFilePath(attribs_class['filename']), """using System;\nusing System.Collections;\nusing System.Collections.Generic;\nusing System.Collections.Specialized;\n\nnamespace Solimar\n{\n   namespace Licensing\n   {\n      namespace Attribs\n      {\n%s\n      }\n   }\n}\n""" % (IndentTextTabs(self.GenerateAttribsClass(attribs_class,0,0),3),))
      
   def TranslateMemberType(self,type):
      if (self.type_map.has_key(type)):
         return self.type_map[type]
      return None
   
   def TranslateMemberTypeUnderlying(self,type):
      if (self.type_map_underlying.has_key(type)):
         return self.type_map_underlying[type]
      return None
   
   # 
   # Helper method for GenerateClassAliasedResourceInitializers()
   # returns code_text 
   #
   # input: [member to examine], xml_parameter_name, cpp initializing function name, enum type to cast parameters to.
   #
   def GenerateResourceInitializerFuncCode(self, member, xml_parm_name, cpp_resfunc_name, cpp_resfunc_enum_type):
      code_text = ""
      #
      # only generate code if this member has specified a setting with the xmlPparm_name.
      #
      if (len (member[xml_parm_name])):
         #
         # setting may consist of multiple values seperated by the |' char.
         # separate these "options" into their own list
         #
         options = member[xml_parm_name].split("|")   
         #
         # generate the function call code.
         #
         code_text += "\n      %s.%s(%s.%s" % (member['name'], cpp_resfunc_name, cpp_resfunc_enum_type, options[0])
         for option in options[1:]:
            code_text += "|%s.%s" % (cpp_resfunc_enum_type, option)
         code_text += ");" 
      return code_text   

   #
   # Helper method used by code which generates constructors.
   # returns code_text 
   #
   def GenerateClassAliasedResourceInitializers(self, members):
      code_text = ""
      for member in OutputOrderDictionaryValues(members):
         for alias_parm in self.aliased_resource_parm_map:
            code_text += self.GenerateResourceInitializerFuncCode(
               member, 
               alias_parm, 
               self.aliased_resource_parm_map[alias_parm][0],
               self.aliased_resource_parm_map[alias_parm][1]
               )
      return code_text
      
   
